from botocore.config import Config
import hashlib

config = Config()
DYNAMO_CLIENT = boto3.client('dynamodb', config=config)


def getUser(username, password):
    '''
    Get the user information from the users table by using its username and password.
    Returns the user item if credentials match, else None.
    '''
    # Hash the provided password for comparison
    password_hash = hashlib.sha256(password.encode('utf-8')).hexdigest()

    try:
        response = DYNAMO_CLIENT.get_item(
            TableName='users',
            Key={
                'username': {'S': username},
            }
        )
        if 'Item' not in response:
            return None

        stored_hash = response['Item'].get('password_hash', {}).get('S')
        if stored_hash is None:
            return None

        if stored_hash == password_hash:
            return response['Item']
        else:
            return None
    except Exception:
        # Do not leak details (CWE-200 mitigation)
        return None
